select v_1 as "nation", v_2 as "o_year", v_3 as "sum_profit" from (select v_4 as v_1, v_5 as v_2, sum(v_6) as v_3 from (select v_4, cast(strftime('%Y', v_7) as integer) as v_5, (v_8 * (1 - v_9)) - (v_10 * v_11) as v_6 from (select * from (select * from (select * from (select * from (select * from (select * from (select "p_partkey" as v_12, "p_name" as v_13, "p_mfgr" as v_14, "p_brand" as v_15, "p_type" as v_16, "p_size" as v_17, "p_container" as v_18, "p_retailprice" as v_19, "p_comment" as v_20 from "part") s where v_13 like '%green%') l inner join (select "l_orderkey" as v_21, "l_partkey" as v_22, "l_suppkey" as v_23, "l_linenumber" as v_24, "l_quantity" as v_11, "l_extendedprice" as v_8, "l_discount" as v_9, "l_tax" as v_25, "l_returnflag" as v_26, "l_linestatus" as v_27, "l_shipdate" as v_28, "l_commitdate" as v_29, "l_receiptdate" as v_30, "l_shipinstruct" as v_31, "l_shipmode" as v_32, "l_comment" as v_33 from "lineitem") r on v_12 = v_22) l inner join (select "s_suppkey" as v_34, "s_name" as v_35, "s_address" as v_36, "s_nationkey" as v_37, "s_phone" as v_38, "s_acctbal" as v_39, "s_comment" as v_40 from "supplier") r on v_34 = v_23) l inner join (select "ps_partkey" as v_41, "ps_suppkey" as v_42, "ps_availqty" as v_43, "ps_supplycost" as v_10, "ps_comment" as v_44 from "partsupp") r on (v_42 = v_23) and (v_41 = v_22)) l inner join (select "o_orderkey" as v_45, "o_custkey" as v_46, "o_orderstatus" as v_47, "o_totalprice" as v_48, "o_orderdate" as v_7, "o_orderpriority" as v_49, "o_clerk" as v_50, "o_shippriority" as v_51, "o_comment" as v_52 from "orders") r on v_45 = v_21) l inner join (select "n_nationkey" as v_53, "n_name" as v_4, "n_regionkey" as v_54, "n_comment" as v_55 from "nation") r on v_37 = v_53) s) s group by 1, 2) s order by v_1, v_2 desc
